import{_ as s,o as a,c as n,U as l}from"./chunks/framework.ee26a04d.js";const p="/blog/assets/image-20230720133241476.212259ae.png",e="/blog/assets/image-20230720134725385.ed484c72.png",t="/blog/assets/image-20230720135905490.d6736f39.png",g=JSON.parse('{"title":"MySQL","description":"","frontmatter":{},"headers":[],"relativePath":"java/MySQL.md","filePath":"java/MySQL.md","lastUpdated":1690097360000}'),o={name:"java/MySQL.md"},c=l('<h1 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to &quot;MySQL&quot;">​</a></h1><h2 id="下载安装" tabindex="-1">下载安装 <a class="header-anchor" href="#下载安装" aria-label="Permalink to &quot;下载安装&quot;">​</a></h2><h3 id="下载步骤" tabindex="-1">下载步骤 <a class="header-anchor" href="#下载步骤" aria-label="Permalink to &quot;下载步骤&quot;">​</a></h3><p>官网下载 zip 安装包</p><p><a href="https://dev.mysql.com/downloads/mysql/5.7.html" target="_blank" rel="noreferrer">MySQL :: Download MySQL Community Server</a></p><p>解压</p><p>添加环境变量</p><p><img src="'+p+`" alt="image-20230720133241476"></p><p>添加配置文件 my.ini,使用安装目录。</p><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">[mysqld]</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#设置3306端口号</span></span>
<span class="line"><span style="color:#F07178;">port</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">3306</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#设置MySQL的安装目录</span></span>
<span class="line"><span style="color:#F07178;">basedir</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">D:\\\\Program Files\\\\MySQL\\\\mysql-5.7.43-winx64</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#设置MySQL数据库的数据存放目录</span></span>
<span class="line"><span style="color:#F07178;">datadir</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">D:\\\\Program Files\\\\MySQL\\\\mysql-5.7.43-winx64\\\\data</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#运行最大连接数</span></span>
<span class="line"><span style="color:#F07178;">max_connections</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">200</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#运行连接失败的次数。这也是为了防止有人从该主机试图攻击数据库系统</span></span>
<span class="line"><span style="color:#F07178;">max_connect_errors</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">10</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#服务端使用的字符集默认为utf-8</span></span>
<span class="line"><span style="color:#F07178;">character-set-server</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">utf8</span></span>
<span class="line"><span style="color:#89DDFF;">[mysql]</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#客户端使用的字符集默认为utf8</span></span>
<span class="line"><span style="color:#F07178;">default-character-set</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">utf8</span></span>
<span class="line"><span style="color:#89DDFF;">[client]</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#客户端默认端口号为3306</span></span>
<span class="line"><span style="color:#F07178;">port</span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;">3306</span></span>
<span class="line"><span style="color:#A6ACCD;">skip-grant-tables</span></span></code></pre></div><p>cmd 管理员模式，进入 bin 目录，输入命令</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">mysqld -install</span></span></code></pre></div><p>初始化数据</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">mysqld --initialize-insecure --user=mysql</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">net start mysql</span></span></code></pre></div><p>再次启动 mysql，进入管理界面。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">mysql -u root -p</span></span></code></pre></div><h3 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h3><p><img src="`+e+'" alt="image-20230720134725385"></p><p>原因：用户名和密码错误，访问失效。</p><p>步骤：</p><p>在 Mysql 下载目录配置文件中找到 my.ini,加上 skip-grant-tables。</p><p>网上的，对我无效。还是网上看的：</p><p>首先停止 mysql 服务：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">net stop mysql</span></span></code></pre></div><p>在 cmd 中输入以下：</p><p>mysqld --defaults-file=&quot;D:\\Program Files\\MySQL\\mysql-5.7.43-winx64\\my.ini&quot; --skip-grant-tables</p><p>中间用 my.ini 路径替换。</p><p>打开另一个 cmd。</p><p>进入 mysql 服务。输入密码时直接回车。</p><p>成功：</p><p><img src="'+t+`" alt="image-20230720135905490"></p><p>别忘了更新密码(分号不能忘)：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">mysql&gt; ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;123456&#39;;</span></span></code></pre></div><h2 id="基本命令行操作" tabindex="-1">基本命令行操作 <a class="header-anchor" href="#基本命令行操作" aria-label="Permalink to &quot;基本命令行操作&quot;">​</a></h2><p>命令行连接</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">mysql -uroot -p123456 -- 链接数据库</span></span>
<span class="line"><span style="color:#A6ACCD;">flush privileges; -- 刷新权限</span></span>
<span class="line"><span style="color:#A6ACCD;">---------------------------------------------------------------</span></span>
<span class="line"><span style="color:#A6ACCD;">show databases; -- 查看所有数据库</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">mysql&gt; use TABLEname -- 切换数据库</span></span>
<span class="line"><span style="color:#A6ACCD;">Database changed</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">--</span></span>
<span class="line"><span style="color:#A6ACCD;">show tables; -- 查看数据库中所有的表</span></span>
<span class="line"><span style="color:#A6ACCD;">create database 数据库名称 -- 新建数据库</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">exit -- 推出链接</span></span></code></pre></div><h2 id="操作数据库" tabindex="-1">操作数据库 <a class="header-anchor" href="#操作数据库" aria-label="Permalink to &quot;操作数据库&quot;">​</a></h2><p>创建数据库</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">CREATE DATABASE [IF NOT EXISTS] db -- 可选项</span></span>
<span class="line"><span style="color:#A6ACCD;">DROP DATABASE [IF EXISTS] db -- 删除数据库</span></span>
<span class="line"><span style="color:#A6ACCD;">use \`database\` -- 选择数据库</span></span>
<span class="line"><span style="color:#A6ACCD;">show database -- 查看所有数据库</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">select * from \`table\` --查看表中所有数据</span></span></code></pre></div>`,40),i=[c];function r(y,d,C,m,A,h){return a(),n("div",null,i)}const u=s(o,[["render",r]]);export{g as __pageData,u as default};
